const PROCESSING_FEE = 5;
const COMPONENT_BLOCK_OF_THREE_PREMIUM = 60;
const COMPONENT_TYPES = ["rune", "moonstone"];

const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function basePremiumFor(item: Item): number {
  return BASE_PREMIUM_BY_TYPE[item.type];
}

function premiumForItems(items: Item[]): number {
  let total = 0;
  const remaining: Item[] = [];
  for (const componentType of COMPONENT_TYPES) {
    const ofType = items.filter((item) => item.type === componentType);
    if (ofType.length === 3) {
      total += COMPONENT_BLOCK_OF_THREE_PREMIUM;
    } else {
      remaining.push(...ofType);
    }
  }
  for (const item of items) {
    if (!COMPONENT_TYPES.includes(item.type)) {
      remaining.push(item);
    }
  }
  total += remaining.reduce((sum, item) => sum + basePremiumFor(item), 0);
  return total;
}
